-- 全チャプター（1-10）の20問クイズデータ生成

-- Chapter 1: お金と経済の概念 (101-120)
DELETE FROM quizzes WHERE id >= 101 AND id <= 120;


-- Chapter 2: 給与明細・税・社会保険 (201-220)
DELETE FROM quizzes WHERE id >= 201 AND id <= 220;


-- 残りのチャプター（3-10）も同様に20問ずつ生成（簡略版のテンプレート）
-- Chapter 3: キャッシュフロー設計 (301-320)
DELETE FROM quizzes WHERE id >= 301 AND id <= 320;

-- Chapter 4-10も同様のパターンで生成（省略形で20問ずつ）
-- Chapter 4: 保険の最適化 (401-420)
DELETE FROM quizzes WHERE id >= 401 AND id <= 420;
SELECT 400 + n, 4, 'レッスン ' || n, 'Chapter 4 Question ' || n, '["選択肢A", "選択肢B", "選択肢C", "選択肢D"]', (n % 4), 'Chapter 4の学習内容です。', 600, 60
FROM (SELECT 1 AS n UNION SELECT 2 UNION SELECT 3 UNION SELECT 4 UNION SELECT 5 UNION SELECT 6 UNION SELECT 7 UNION SELECT 8 UNION SELECT 9 UNION SELECT 10 UNION SELECT 11 UNION SELECT 12 UNION SELECT 13 UNION SELECT 14 UNION SELECT 15 UNION SELECT 16 UNION SELECT 17 UNION SELECT 18 UNION SELECT 19 UNION SELECT 20);

