INSERT INTO quizzes (id, chapter_id, title, question, options, correct_answer, explanation, reward, xp) VALUES
(101, 1, 'インフレと預金', 'インフレ時に預金の価値はどうなりますか？', '["増える", "減る", "変わらない", "倍になる"]', 1, 'インフレで物価が上がると、同じ金額でも買えるものが減るので実質的に価値が減ります。', 300, 30),
(102, 1, '実質賃金', '物価上昇率が3%、賃金上昇率が2%の場合、実質賃金は？', '["1%増加", "1%減少", "5%増加", "変わらない"]', 1, '実質賃金 = 賃金上昇率 - 物価上昇率 = 2% - 3% = -1%（減少）', 300, 30),
(103, 1, '円安と物価', '円安になると輸入品の価格はどうなりますか？', '["安くなる", "高くなる", "変わらない", "半額になる"]', 1, '円の価値が下がると、外国通貨建ての輸入品は円建てで高くなります。', 300, 30),
(104, 1, '複利効果', '100万円を年利5%で10年運用した場合、単利と複利の差は？', '["ほぼ同じ", "複利が大幅に多い", "単利が多い", "同額"]', 1, '複利では利息が利息を生むため、長期では差が大きくなります。', 300, 30),
(105, 1, '72の法則', '年利6%で運用すると、資産が2倍になる年数は？', '["6年", "12年", "18年", "24年"]', 1, '72の法則: 72 ÷ 6 = 12年で2倍になります。', 300, 30),
(106, 1, '現金のリスク', '現金保有の最大のリスクは？', '["盗難", "インフレ", "破損", "偽札"]', 1, 'インフレにより、現金の購買力が徐々に減少していきます。', 300, 30),
(107, 1, '長期投資', '長期投資の主なメリットは？', '["短期利益", "複利効果", "リスクゼロ", "元本保証"]', 1, '長期投資では複利効果が働き、時間とともに資産が大きく成長します。', 300, 30),
(108, 1, '現在価値', '1年後の110万円は、年利10%で割り引くと現在価値は？', '["100万円", "110万円", "120万円", "90万円"]', 0, '現在価値 = 110万円 ÷ 1.10 = 100万円', 300, 30),
(109, 1, '低金利時代', '低金利時代の最適な資産運用は？', '["預金のみ", "投資も検討", "タンス預金", "何もしない"]', 1, '低金利では預金の利息が少ないため、リスク分散しながら投資も検討すべきです。', 300, 30),
(110, 1, '投資の3要素', '投資の3要素は「安全性・流動性・...」？', '["利便性", "収益性", "簡便性", "確実性"]', 1, '投資の3要素は「安全性・流動性・収益性」です。', 300, 30),
(111, 1, '時間価値', 'お金の時間価値とは？', '["時間と共に増える", "今の1万円と未来の1万円の価値は同じ", "時間と共に減る", "時計の価値"]', 0, '同じ金額でも、今受け取る方が投資できるため価値が高いという概念です。', 300, 30),
(112, 1, 'デフレの影響', 'デフレ時に得をするのは？', '["借金がある人", "現金保有者", "輸出企業", "不動産投資家"]', 1, 'デフレでは物価が下がるため、現金の購買力が上がります。', 300, 30),
(113, 1, '金利と債券', '金利が上昇すると債券価格は？', '["上昇", "下落", "変わらない", "倍増"]', 1, '金利上昇時、既存の低金利債券の魅力が下がるため価格が下落します。', 300, 30),
(114, 1, 'GDP', 'GDPとは何の略？', '["国内総生産", "国民総生産", "政府総支出", "企業総利益"]', 0, 'GDP = Gross Domestic Product（国内総生産）', 300, 30),
(115, 1, '景気循環', '景気の4局面は「好況・後退・不況・...」？', '["停滞", "回復", "成長", "安定"]', 1, '景気循環の4局面：好況→後退→不況→回復', 300, 30),
(116, 1, '為替レート', '1ドル=100円から150円になると？', '["円高", "円安", "変化なし", "為替安定"]', 1, 'より多くの円が必要になるため、円の価値が下がった（円安）ことを意味します。', 300, 30),
(117, 1, 'CPI', 'CPI（消費者物価指数）は何を測る？', '["物価変動", "失業率", "GDP成長", "為替レート"]', 0, 'CPIは消費者が購入する商品・サービスの価格変動を測る指標です。', 300, 30),
(118, 1, '名目と実質', '名目GDPと実質GDPの違いは？', '["インフレ調整の有無", "国内外の違い", "企業規模の違い", "税金の有無"]', 0, '実質GDPは物価変動の影響を除いた実際の経済成長を示します。', 300, 30),
(119, 1, '機会費用', '機会費用とは？', '["失われた機会の価値", "実際の支払額", "利息の総額", "税金"]', 0, 'ある選択をすることで失われた、他の選択肢の価値のことです。', 300, 30),
(120, 1, 'リスクとリターン', '一般的にリスクとリターンの関係は？', '["比例する", "反比例する", "無関係", "リスクのみ高い"]', 0, '高リスクには高リターンの可能性、低リスクには低リターンという関係があります。', 300, 30);
INSERT INTO quizzes (id, chapter_id, title, question, options, correct_answer, explanation, reward, xp) VALUES
(201, 2, '給与天引き', '給与明細の「控除」とは？', '["追加支給", "天引き項目", "ボーナス", "手当"]', 1, '控除とは税金や社会保険料など給与から差し引かれる項目です。', 400, 40),
(202, 2, '住民税', '住民税はいつの所得に対して課税される？', '["当年", "前年", "翌年", "過去3年"]', 1, '住民税は前年の所得に基づいて当年に課税されます。', 400, 40),
(203, 2, '所得税制度', '所得税の税率は所得が増えると？', '["下がる", "上がる", "変わらない", "ゼロになる"]', 1, '日本の所得税は累進課税制度で、所得が増えるほど税率が上がります。', 400, 40),
(204, 2, '健康保険', '健康保険料は誰が負担する？', '["会社のみ", "本人のみ", "会社と本人", "国"]', 2, '健康保険料は会社と本人が折半で負担します。', 400, 40),
(205, 2, '厚生年金', '厚生年金の加入条件は？', '["正社員のみ", "週20時間以上勤務等", "年収500万以上", "誰でも可"]', 1, '週20時間以上勤務など一定条件を満たせばパートでも加入できます。', 400, 40),
(206, 2, '雇用保険', '雇用保険の主な給付は？', '["医療費補助", "失業手当", "年金", "住宅補助"]', 1, '雇用保険は失業時の生活を支援する失業手当が主な給付です。', 400, 40),
(207, 2, '扶養控除', '扶養控除を受けられるのは？', '["誰でも", "条件を満たす家族がいる場合", "独身者のみ", "既婚者のみ"]', 1, '年間所得が一定以下の家族を扶養している場合に適用されます。', 400, 40),
(208, 2, '配偶者控除', '配偶者控除の年収の壁は？', '["103万円", "130万円", "150万円", "200万円"]', 0, '配偶者の年収が103万円以下の場合、配偶者控除が適用されます。', 400, 40),
(209, 2, '基礎控除', '基礎控除は誰が受けられる？', '["高所得者のみ", "全員", "低所得者のみ", "申請者のみ"]', 1, '基礎控除は全ての納税者が受けられる控除です（所得制限あり）。', 400, 40),
(210, 2, '医療費控除', '医療費控除を受けられる最低額は？', '["5万円", "10万円", "15万円", "20万円"]', 1, '年間医療費が10万円（または所得の5%）を超えた場合に控除できます。', 400, 40),
(211, 2, 'ふるさと納税', 'ふるさと納税の実質負担額は？', '["0円", "2,000円", "5,000円", "10,000円"]', 1, 'ふるさと納税は2,000円の自己負担で返礼品がもらえる制度です。', 400, 40),
(212, 2, '源泉徴収', '源泉徴収とは？', '["年末調整", "給与からの税金天引き", "確定申告", "還付申告"]', 1, '源泉徴収は給与支払い時に所得税を天引きする制度です。', 400, 40),
(213, 2, '年末調整', '年末調整で還付される可能性が高いのは？', '["独身", "扶養家族が多い", "高所得", "新入社員"]', 1, '扶養家族が多いと控除が増え、還付される可能性が高まります。', 400, 40),
(214, 2, '確定申告', '確定申告が必要なのは？', '["全員", "給与以外の所得がある人", "サラリーマンのみ", "年金受給者のみ"]', 1, '給与以外に所得がある場合や、医療費控除等を受ける場合に必要です。', 400, 40),
(215, 2, '社会保険料', '社会保険料の計算基準は？', '["基本給のみ", "標準報酬月額", "手取り額", "年収"]', 1, '標準報酬月額（給与を一定の幅で区分した額）が基準になります。', 400, 40),
(216, 2, '介護保険', '介護保険料の徴収開始年齢は？', '["20歳", "40歳", "60歳", "65歳"]', 1, '40歳から介護保険料の徴収が始まります。', 400, 40),
(217, 2, '賞与', '賞与から引かれる社会保険料は？', '["引かれない", "引かれる", "選択制", "会社による"]', 1, '賞与からも社会保険料は天引きされます。', 400, 40),
(218, 2, '所得の種類', '給与所得以外の所得は？', '["事業所得のみ", "配当・不動産等", "年金のみ", "存在しない"]', 1, '事業所得、配当所得、不動産所得など10種類の所得があります。', 400, 40),
(219, 2, '退職金', '退職金の課税方法は？', '["全額非課税", "分離課税", "給与と合算", "課税なし"]', 1, '退職金は退職所得として分離課税され、優遇されています。', 400, 40),
(220, 2, 'iDeCo', 'iDeCoの掛金の税制上のメリットは？', '["課税される", "所得控除", "非課税", "損益通算"]', 1, 'iDeCoの掛金は全額所得控除の対象となり、税負担が軽減されます。', 400, 40);
INSERT INTO quizzes (id, chapter_id, title, question, options, correct_answer, explanation, reward, xp) VALUES
(301, 3, 'レッスン 1', 'キャッシュフロー設計の基本は？', '["支出を無視", "収入と支出の管理", "投資のみ", "貯金のみ"]', 1, '収入と支出を適切に管理することがキャッシュフロー設計の基本です。', 500, 50),
(302, 3, 'レッスン 2', '生活防衛資金の目安は？', '["1ヶ月分", "3-6ヶ月分", "1年分", "不要"]', 1, '一般的に生活費の3-6ヶ月分の貯蓄が推奨されます。', 500, 50),
(303, 3, 'レッスン 3', '固定費を減らすメリットは？', '["なし", "継続的な支出削減", "一時的節約", "収入増"]', 1, '固定費削減は毎月継続的に効果があります。', 500, 50),
(304, 3, 'レッスン 4', '変動費の管理方法は？', '["無視する", "予算を決める", "使い放題", "記録不要"]', 1, '月の予算を決めて管理するのが効果的です。', 500, 50),
(305, 3, 'レッスン 5', '家計簿をつけるメリットは？', '["手間だけ", "支出の見える化", "必須ではない", "時間の無駄"]', 1, '支出を見える化することで無駄が分かります。', 500, 50),
(306, 3, 'レッスン 6', 'クレジットカードの注意点は？', '["使い放題", "使いすぎリスク", "安全", "デメリットなし"]', 1, '使いすぎや支払い遅延のリスクに注意が必要です。', 500, 50),
(307, 3, 'レッスン 7', '先取り貯金の効果は？', '["効果なし", "確実に貯蓄できる", "後回しで良い", "必要ない"]', 1, '給料が入ったらすぐ貯金することで確実に貯まります。', 500, 50),
(308, 3, 'レッスン 8', '収入の何割を貯蓄すべき？', '["0%", "10-20%", "50%", "全額"]', 1, '収入の10-20%を貯蓄に回すのが一般的です。', 500, 50),
(309, 3, 'レッスン 9', '予算管理の鉄則は？', '["予算なし", "収入-支出を管理", "支出のみ", "記録不要"]', 1, '収入から支出を引いて余剰を確認することが大切です。', 500, 50),
(310, 3, 'レッスン 10', '無駄な支出を見つける方法は？', '["感覚", "支出記録の分析", "無視", "他人に聞く"]', 1, '支出記録を分析することで無駄が見えてきます。', 500, 50),
(311, 3, 'レッスン 11', 'ボーナスの使い道は？', '["全額消費", "一部貯蓄", "全額貯金", "借金返済のみ"]', 1, '一部を貯蓄や投資に回すのが賢明です。', 500, 50),
(312, 3, 'レッスン 12', '緊急時資金は何に使う？', '["旅行", "急な出費", "投資", "趣味"]', 1, '病気や失業など予期せぬ出費に備えます。', 500, 50),
(313, 3, 'レッスン 13', '住宅ローンの返済期間は？', '["短いほど良い", "長いほど良い", "柔軟に考える", "関係ない"]', 2, '金利や返済能力を考慮して柔軟に決めるべきです。', 500, 50),
(314, 3, 'レッスン 14', '自動車の維持費は？', '["購入費のみ", "保険・税金・ガソリン等", "無料", "不要"]', 1, '保険、税金、ガソリン、車検など継続的にかかります。', 500, 50),
(315, 3, 'レッスン 15', '教育費の準備方法は？', '["不要", "計画的に積立", "借金で対応", "その場しのぎ"]', 1, '子供の進学時期に合わせて計画的に積み立てます。', 500, 50),
(316, 3, 'レッスン 16', '保険料の見直し時期は？', '["不要", "定期的に", "一度加入したら変更不要", "解約のみ"]', 1, 'ライフステージの変化に合わせて定期的に見直します。', 500, 50),
(317, 3, 'レッスン 17', '通信費の節約方法は？', '["変更不可", "格安プランへ変更", "最高プランのみ", "放置"]', 1, '格安SIMや必要なプランへの見直しで節約できます。', 500, 50),
(318, 3, 'レッスン 18', 'サブスク見直しの効果は？', '["なし", "固定費削減", "増額", "意味なし"]', 1, '使っていないサブスクを解約すれば固定費が減ります。', 500, 50),
(319, 3, 'レッスン 19', '外食費の管理方法は？', '["制限なし", "月予算を決める", "禁止", "毎日外食"]', 1, '月の外食予算を決めて管理するのが効果的です。', 500, 50),
(320, 3, 'レッスン 20', 'ポイント活用のコツは？', '["無視", "計画的に貯めて使う", "貯めない", "現金のみ"]', 1, '計画的にポイントを貯めて必要なものに使うと節約になります。', 500, 50);
